class Solution {
    public int maxTaskAssign(int[] tasks, int[] workers, int pills, int strength) {
        Arrays.sort(tasks);
        Arrays.sort(workers);
        int taskCount = 0;
        int workerIndex = 0;
        for (int i = 0; i < tasks.length; i++) {
            if (workerIndex < workers.length && workers[workerIndex] >= tasks[i]) {
                taskCount++;
                workerIndex++;
            } else if (pills > 0) {
                workers[workerIndex] += strength;
                if (workers[workerIndex] >= tasks[i]) {
                    taskCount++;
                }
                pills--;
            }
        }
        return taskCount;
    }
}
```
